#include <torch/extension.h>
#include <cuda_runtime.h>

// Problem 016 — RoPE inverse-frequency initialization.
//
//   inv_freq[i] = 1.0 / rope_theta^(2*i / head_dim)
//               = 1.0 / rope_theta^(i / 64.0)      for i in [0, 64)
//
// This is pure launch-latency/latency bound.  One elementwise kernel handles
// all work directly from threadIdx.x with no input tensor reads and no
// intermediate allocations.  Compiled with -O3 --use_fast_math it maps to a
// single CUDA kernel launch that writes only the 256 B output.

constexpr int HEAD_DIM = 128;
constexpr int N = HEAD_DIM / 2;  // 64

__global__ void rope_inv_freq_kernel(float* __restrict__ out, float rope_theta)
{
    const int i = threadIdx.x;
    if (i < N) {
        const float exponent = static_cast<float>(i) / static_cast<float>(N);
        out[i] = 1.0f / powf(rope_theta, exponent);
    }
}

// Entry point called by the harness.  CUDA binding is performed by the
// PYBIND11_MODULE stanza below.
torch::Tensor run(float rope_theta)
{
    auto out = torch::empty(
        {N},
        torch::TensorOptions()
            .dtype(torch::kFloat32)
            .device(torch::kCUDA));

    rope_inv_freq_kernel<<<1, N>>>(out.data_ptr<float>(), rope_theta);
    return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m)
{
    m.def("run", &run, "RoPE inverse frequency (float scalar -> (64,) fp32)");
}

